import styled from 'styled-components';

const H1 = styled.h1`
 font-size: 2rem;
 color: #bc9552;
 text-align: center;
`;

const App = () => {
 return (
  &lt;>
   &lt;H1>My App&lt;/H1>
  &lt;/>
 )
}

// Eltern-Element

import styled from 'styled-components';
import Child from "./Child.jsx";

const StyledChild = styled(Child)` color: #f00; `;

const App = () => {
 return (
  &lt;>
   &lt;H1>My App&lt;/H1>
   &lt;Child />
   &lt;StyledChild  />
  &lt;/>
 )
}

export default App

// Kind-Element Child.jsx

const Child = ({className}) => {
 return (
  &lt;>
   &lt;div>
    &lt;h2>Kind-Element&lt;/h2>
    &lt;p className={className}>Hallo Welt&lt;/p>
   &lt;/div>
  &lt;/>
 )
}

export default Child;

import styled from 'styled-components';
import Child from "./Child.jsx";
import {useState} from "react";

const App = () => {

 const [primary, setPrimary] = useState(false)
 const StyledP = styled.p`
  color: ${primary ? '#f00' : '#abc'};
 `

 return (
  &lt;>
   &lt;h1>My App&lt;/h1>
   &lt;StyledP>I am styled&lt;/StyledP>
   &lt;button onClick={() => setPrimary(!primary)}>Change&lt;/button>
  &lt;/>
 )
}

export default App

import styled from 'styled-components';

const StyledButton = styled.button`
 background-color: #4CAF50;
 color: white;
 padding: 10px 20px;
 display: inline-block;
 margin: 4px 2px;
 cursor: pointer;
 border-radius: 8px;
 transition: background-color 0.3s ease; 

 &:hover {
  background-color: #45a049;
 }

`;

// Verwendung
const App = () => &lt;StyledButton>Hover mich!&lt;/StyledButton>;
